var EDITOR_SELECTOR = "[data-article-editor]";
function allMatching(container) {
  const matches2 = Array.from(container.querySelectorAll(EDITOR_SELECTOR));
  if (container instanceof HTMLElement && container.matches(EDITOR_SELECTOR))
    matches2.push(container);
  return matches2;
}
function initAll(container) {
  allMatching(container).forEach(mountEditor);
}
document.addEventListener("click", (event) => {
  const target = event.target instanceof Element ? event.target : null;
  const toolButton = target?.closest("[data-md-action]");
  if (toolButton) {
    const root = editorRoot(toolButton);
    if (!root || root.dataset.editorMode !== "wysiwyg")
      return;
    const editor = editors.get(root);
    const action = TOOLBAR_ACTIONS[toolButton.dataset.mdAction ?? ""];
    if (editor && action) {
      event.preventDefault();
      event.stopImmediatePropagation();
      action(editor, root);
    }
    return;
  }
  const modeToggle = target?.closest("[data-article-mode-toggle]");
  if (modeToggle) {
    const root = editorRoot(modeToggle);
    if (!root)
      return;
    event.preventDefault();
    setMode(root, root.dataset.editorMode === "source" ? "wysiwyg" : "source");
  }
}, true);
document.body.addEventListener("htmx:afterSwap", (event) => {
  const target = event.detail?.target;
  initAll(target instanceof Element ? target : document);
});
document.body.addEventListener("htmx:beforeSwap", (event) => {
  const target = event.detail?.target;
  if (!(target instanceof Element))
    return;
  allMatching(target).forEach(destroyEditor);
});
initAll(document);
